const payload = $input.first().json.body || $input.first().json;

const errorDetails = {
  repository: payload.repository?.full_name || 'unknown',
  workflow_name: payload.workflow?.name || payload.workflow_run?.name || 'unknown',
  workflow_id: payload.workflow_run?.id || 'unknown',
  run_id: payload.workflow_run?.id || payload.check_run?.id || 'unknown',
  conclusion: payload.workflow_run?.conclusion || payload.check_run?.conclusion || 'failure',
  error_logs_url: payload.workflow_run?.logs_url || '',
  html_url: payload.workflow_run?.html_url || payload.check_run?.html_url || '',
  head_branch: payload.workflow_run?.head_branch || 'main',
  head_sha: payload.workflow_run?.head_sha || '',
  triggered_by: payload.sender?.login || 'unknown',
  timestamp: new Date().toISOString()
};

return { json: errorDetails };

const sessionId = $('Airtop - Create Browser Session').item.json.data.id;
const url = $input.first().json.url;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.airtop.ai/v1/sessions/${sessionId}/windows`,
  headers: {
    'Authorization': 'Bearer ' + $credentials.airtopApi.apiKey,
    'Content-Type': 'application/json'
  },
  body: { url: url }
});

return { json: { windowId: response.data.id, sessionId: sessionId } };

const sessionId = $input.first().json.sessionId;
const windowId = $input.first().json.windowId;
const prompt = $input.first().json.prompt || 'Extract all error messages and logs from this page';

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.airtop.ai/v1/sessions/${sessionId}/windows/${windowId}/page-query`,
  headers: {
    'Authorization': 'Bearer ' + $credentials.airtopApi.apiKey,
    'Content-Type': 'application/json'
  },
  body: {
    prompt: prompt,
    configuration: {
      outputSchema: {
        type: 'object',
        properties: {
          content: { type: 'string' },
          errors: { type: 'array', items: { type: 'string' } },
          suggestions: { type: 'array', items: { type: 'string' } }
        }
      }
    }
  }
});

return { json: response.data };

const sessionId = $input.first().json.sessionId;
const windowId = $input.first().json.windowId;
const elementDescription = $input.first().json.elementDescription;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.airtop.ai/v1/sessions/${sessionId}/windows/${windowId}/click`,
  headers: {
    'Authorization': 'Bearer ' + $credentials.airtopApi.apiKey,
    'Content-Type': 'application/json'
  },
  body: { elementDescription: elementDescription }
});

return { json: { success: true, action: 'clicked', element: elementDescription } };

const sessionId = $input.first().json.sessionId;
const windowId = $input.first().json.windowId;
const text = $input.first().json.text;
const elementDescription = $input.first().json.elementDescription;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.airtop.ai/v1/sessions/${sessionId}/windows/${windowId}/type`,
  headers: {
    'Authorization': 'Bearer ' + $credentials.airtopApi.apiKey,
    'Content-Type': 'application/json'
  },
  body: { text: text, elementDescription: elementDescription }
});

return { json: { success: true, action: 'typed', text: text } };

const sessionId = $input.first().json.sessionId;
const windowId = $input.first().json.windowId;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.airtop.ai/v1/sessions/${sessionId}/windows/${windowId}/screenshot`,
  headers: {
    'Authorization': 'Bearer ' + $credentials.airtopApi.apiKey,
    'Content-Type': 'application/json'
  }
});

return { json: { screenshot: response.data.dataUrl } };

